import{c as a,Q as n,j as i,m as t}from"./chunks/framework.Bhbi9jCp.js";const c=JSON.parse('{"title":"文件系统","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/19-文件系统.md","filePath":"osLearning/19-文件系统.md","lastUpdated":1781095972000}'),p={name:"osLearning/19-文件系统.md"};function e(l,s,h,o,d,r){return n(),i("div",null,[...s[0]||(s[0]=[t(`<h1 id="文件系统" tabindex="-1">文件系统 <a class="header-anchor" href="#文件系统" aria-label="Permalink to &quot;文件系统&quot;">​</a></h1><p>上一篇留了个钩子:write 返回成功,数据其实还在内存里飘着。这一篇就把&quot;从 write 到磁盘&quot;这条路走完。你会发现存储领域那些&quot;玄学&quot;:为什么数据库压测 TPS 忽高忽低、为什么有人断电后配置文件变成 0 字节、为什么 Kafka 顺序写能跑满磁盘带宽而你的服务写几个小文件就 IO 打满——<strong>全都不玄,全是文件系统在性能、空间和崩溃一致性(crash consistency)三者之间做的取舍</strong>。看不见取舍的人觉得玄,看见了就只是工程。</p><blockquote><p>一句话先记住:<strong>文件系统 = 命名空间 + 元数据 + 数据块分配 + 崩溃一致性,前三个解决&quot;怎么存&quot;,最后一个解决&quot;断电不坏&quot;</strong>。普通 write 只进页缓存,fsync 才推到持久层;journal 不是为了快,是为了断电之后文件系统结构不散架。</p></blockquote><hr><h2 id="一、块设备只会一件事-按号读写块" tabindex="-1">一、块设备只会一件事:按号读写块 <a class="header-anchor" href="#一、块设备只会一件事-按号读写块" aria-label="Permalink to &quot;一、块设备只会一件事:按号读写块&quot;">​</a></h2><p>先看文件系统的&quot;原材料&quot;有多原始。磁盘 / SSD 作为块设备,对上只提供两个操作:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>read  block 123</span></span>
<span class="line"><span>write block 456</span></span></code></pre></div><p>没有文件名,没有目录,没有权限,没有&quot;追加&quot;,没有大小的概念——就是一个巨大的、按块编号的字节数组。而你想要的是:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/var/log/app.log        ← 人类可读的路径</span></span>
<span class="line"><span>append 1KB              ← 往后加,别覆盖别人</span></span>
<span class="line"><span>rename conf.tmp → conf  ← 原子换名</span></span>
<span class="line"><span>chmod 0644              ← 权限</span></span>
<span class="line"><span>ls /var/log             ← 列目录</span></span></code></pre></div><p>从&quot;块数组&quot;到&quot;文件树&quot;之间的全部落差,就是文件系统的工作清单:</p><ul><li><strong>路径 → inode 的映射</strong>(目录就是一张名字表,18 篇讲过)</li><li><strong>inode → 数据块的映射</strong>(这个文件的第 N 个字节在哪个块上)</li><li><strong>空闲空间管理</strong>(哪些块没人用,分配时尽量连续)</li><li><strong>权限与时间戳</strong></li><li><strong>崩溃恢复</strong>(写到一半断电,怎么不变成废墟)</li><li><strong>缓存与预读</strong>(和页缓存配合,让热数据不碰盘)</li></ul><p>这份清单里最难、也最容易被程序员忽略的,是倒数第二项。先把读写路径走通,再回来收拾它。</p><hr><h2 id="二、一次读写的完整路径" tabindex="-1">二、一次读写的完整路径 <a class="header-anchor" href="#二、一次读写的完整路径" aria-label="Permalink to &quot;二、一次读写的完整路径&quot;">​</a></h2><h3 id="_2-1-读-热的是内存-冷的才是磁盘" tabindex="-1">2.1 读:热的是内存,冷的才是磁盘 <a class="header-anchor" href="#_2-1-读-热的是内存-冷的才是磁盘" aria-label="Permalink to &quot;2.1 读:热的是内存,冷的才是磁盘&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>read(fd)</span></span>
<span class="line"><span>  → VFS</span></span>
<span class="line"><span>  → 查页缓存</span></span>
<span class="line"><span>      命中:拷贝到用户态,结束(百 ns 级)</span></span>
<span class="line"><span>      未命中:</span></span>
<span class="line"><span>        文件系统把&quot;文件内第 N 页&quot;翻译成&quot;设备上第几块&quot;</span></span>
<span class="line"><span>        → 块层(合并、排序、调度)</span></span>
<span class="line"><span>        → 设备执行 IO(SSD 几十 µs,机械盘几 ms)</span></span>
<span class="line"><span>        → 数据填进页缓存</span></span>
<span class="line"><span>        → 拷贝到用户态</span></span></code></pre></div><p>同一行 <code>read</code> 代码,命中和不命中差三四个数量级。<strong>&quot;这个接口平时 1ms,偶尔 200ms&quot;的抖动,很多就是冷数据落到了真实磁盘上</strong>。</p><h3 id="_2-2-写-全篇最重要的一张图" tabindex="-1">2.2 写:全篇最重要的一张图 <a class="header-anchor" href="#_2-2-写-全篇最重要的一张图" aria-label="Permalink to &quot;2.2 写:全篇最重要的一张图&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>write(fd, buf, n)</span></span>
<span class="line"><span>   │</span></span>
<span class="line"><span>   ▼</span></span>
<span class="line"><span>┌─────────────────────┐</span></span>
<span class="line"><span>│ 页缓存(标记 dirty)   │ ← write 到这里就返回&quot;成功&quot;!</span></span>
<span class="line"><span>└─────────┬───────────┘</span></span>
<span class="line"><span>          │ 后台 writeback(秒级延迟,批量)</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>┌─────────────────────┐</span></span>
<span class="line"><span>│ 文件系统(journal/分配)│ ← 决定块怎么写、先写什么</span></span>
<span class="line"><span>└─────────┬───────────┘</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>┌─────────────────────┐</span></span>
<span class="line"><span>│ 块层 + 设备缓存       │ ← 设备自己还有一层易失缓存</span></span>
<span class="line"><span>└─────────┬───────────┘</span></span>
<span class="line"><span>          ▼</span></span>
<span class="line"><span>┌─────────────────────┐</span></span>
<span class="line"><span>│ 持久介质              │ ← 到这里,断电才真的不丢</span></span>
<span class="line"><span>└─────────────────────┘</span></span></code></pre></div><p><code>write</code> 在第一层就返回了,所以它快;但<strong>从第一层到最后一层之间的任何时刻断电,这笔数据都可能没了</strong>。要把数据一路压到底,必须:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, buf, n);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fsync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          // 等数据穿过所有层、设备确认持久化,才返回</span></span></code></pre></div><p>fsync 慢,慢得理直气壮——它等的是真实世界的物理写入。系统的 dirty 水位由 <code>vm.dirty_ratio</code> / <code>vm.dirty_background_ratio</code> 控制,排查 writeback 积压看:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/meminfo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Dirty|Writeback&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vm.dirty_ratio</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vm.dirty_background_ratio</span></span></code></pre></div><hr><h2 id="三、断电名场面与-journal" tabindex="-1">三、断电名场面与 journal <a class="header-anchor" href="#三、断电名场面与-journal" aria-label="Permalink to &quot;三、断电名场面与 journal&quot;">​</a></h2><p>现在看最难的部分。&quot;创建一个文件&quot;在你眼里是一个动作,在文件系统眼里是<strong>至少五次相互关联的写</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 分配一个 inode</span></span>
<span class="line"><span>2. 分配数据块</span></span>
<span class="line"><span>3. 往父目录写目录项(名字 → inode)</span></span>
<span class="line"><span>4. 更新 inode 元数据(大小、块指针)</span></span>
<span class="line"><span>5. 更新空闲块位图</span></span></code></pre></div><p>这五步不可能在一次磁盘写里完成。<strong>如果写到第三步断电</strong>,重启后的文件系统可能是:</p><ul><li>inode 分配了,但没有任何目录指向它(空间凭空消失)</li><li>目录项指向一个不存在的 inode(打开就报错)</li><li>位图说这块空闲,实际有文件在用(下次分配直接写穿别人的数据)</li></ul><p>最后一种最恐怖——<strong>不是丢一个文件,是文件系统结构性损坏,会持续扩散</strong>。早年的解法是开机跑 <code>fsck</code> 全盘扫描修复,TB 级磁盘要扫几个小时。</p><p>journal(日志)的思路简单到漂亮,就是数据库 WAL 的同款:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 先把&quot;我打算做哪些修改&quot;完整写进一块专用日志区</span></span>
<span class="line"><span>2. 等日志落盘(这是一次顺序写,快)</span></span>
<span class="line"><span>3. 再去真正修改文件系统的各处结构</span></span>
<span class="line"><span>4. 崩溃重启后:日志完整 → 重放(replay);日志不完整 → 整条丢弃</span></span></code></pre></div><p>要么全做,要么全不做——<strong>单次操作的原子性,用&quot;先声明后动手&quot;换来了</strong>。代价是元数据要写两遍(一遍日志一遍原地),所以说 journal 不是性能优化,是花性能买安全。</p><h3 id="ext4-的三档安全等级" tabindex="-1">ext4 的三档安全等级 <a class="header-anchor" href="#ext4-的三档安全等级" aria-label="Permalink to &quot;ext4 的三档安全等级&quot;">​</a></h3><p>journal 保护到什么程度,ext4 给你选:</p><table tabindex="0"><thead><tr><th>模式</th><th>保护范围</th><th>速度</th><th>一句话</th></tr></thead><tbody><tr><td><code>data=journal</code></td><td>数据 + 元数据都进日志</td><td>最慢</td><td>一切写两遍,最稳</td></tr><tr><td><code>data=ordered</code>(默认)</td><td>元数据进日志,<strong>数据先于元数据落盘</strong></td><td>折中</td><td>结构不坏,内容自理</td></tr><tr><td><code>data=writeback</code></td><td>只有元数据进日志,数据顺序不保证</td><td>最快</td><td>崩溃后文件可能含旧垃圾数据</td></tr></tbody></table><p>默认的 ordered 是个很工程化的折中:<strong>文件系统自身结构保证不坏,但你的数据内容要不要持久,仍然归你的 fsync 管</strong>。换句话说,journal 保护的是文件系统,不是你——这个分工必须想清楚。</p><hr><h2 id="四、fsync-为什么能慢成性能瓶颈" tabindex="-1">四、fsync 为什么能慢成性能瓶颈 <a class="header-anchor" href="#四、fsync-为什么能慢成性能瓶颈" aria-label="Permalink to &quot;四、fsync 为什么能慢成性能瓶颈&quot;">​</a></h2><p>知道了下盘路径,fsync 的慢就能拆出来了:</p><ul><li><strong>设备延迟</strong>——它必须等物理介质确认,机械盘一次寻道几 ms</li><li><strong>journal commit</strong>——你的 fsync 可能要先等一笔 journal 事务提交</li><li><strong>写放大</strong>——改 1 字节,可能要写整页、写日志、写元数据</li><li><strong>flush 竞争</strong>——多个文件同时 fsync,在设备队列里排队</li><li><strong>云盘抖动</strong>——云厂商的块存储后端延迟方差很大,p99 难看是常态</li><li><strong>RAID / 设备缓存策略</strong>——带电池缓存的 RAID 卡 fsync 飞快,没有的老老实实等盘</li></ul><p>名场面:某团队自研存储,&quot;每写一条记录 fsync 一次保证不丢&quot;,压测 TPS 只有 200——因为机械盘一秒就只能做这么多次持久化确认。<strong>数据库性能工程的相当一部分,就是在和 fsync 搏斗</strong>,套路也早已成熟:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每事务一次 fsync 太慢</span></span>
<span class="line"><span>  → group commit:攒一批事务,一次 fsync 摊薄成本</span></span>
<span class="line"><span>随机写数据页太慢</span></span>
<span class="line"><span>  → WAL 顺序写 + 落盘,数据页留在内存后台慢慢刷</span></span></code></pre></div><p>MySQL 的 redo log、PostgreSQL 的 WAL、Kafka 的顺序追加,全是这一个思路的变奏:<strong>把&quot;必须持久&quot;的部分变成顺序写,把随机写推到后台</strong>。</p><hr><h2 id="五、原子更新配置-write-fsync-rename" tabindex="-1">五、原子更新配置:write + fsync + rename <a class="header-anchor" href="#五、原子更新配置-write-fsync-rename" aria-label="Permalink to &quot;五、原子更新配置:write + fsync + rename&quot;">​</a></h2><p>另一个名场面:程序更新配置文件,直接打开原文件覆盖写,写到一半进程被 kill / 断电——重启后配置文件半新半旧,或者干脆 0 字节,服务起不来。</p><p>标准答案是个五步套路,值得背下来:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> open</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;conf.tmp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, O_CREAT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">O_WRONLY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">O_TRUNC, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">644</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, data, len);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fsync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                    // 1. 新内容先持久化</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">close</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rename</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;conf.tmp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;conf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   // 2. 原子换名</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fsync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(dirfd);</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                 // 3. 目录项更新也要落盘</span></span></code></pre></div><p>它能成立靠的是一条文件系统承诺:<strong>rename 在同一文件系统内是原子的</strong>——任何时刻去读,要么拿到完整的旧文件,要么拿到完整的新文件,绝不会看到写了一半的中间态。</p><p>两个容易漏的细节:rename 之前必须 fsync 文件本身,否则可能出现&quot;名字换过去了,内容还没落盘&quot;,断电后得到一个空的新文件;rename 之后还要 fsync 目录,因为&quot;名字 → inode&quot;这条目录项本身也是数据,也可能丢。<strong>漏掉目录 fsync 的代码,平时一点问题没有,断电那天专门坑你</strong>。</p><hr><h2 id="六、ext4-xfs-btrfs-怎么选" tabindex="-1">六、ext4 / XFS / btrfs:怎么选 <a class="header-anchor" href="#六、ext4-xfs-btrfs-怎么选" aria-label="Permalink to &quot;六、ext4 / XFS / btrfs:怎么选&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>ext4</th><th>XFS</th><th>btrfs</th></tr></thead><tbody><tr><td>定位</td><td>通用默认</td><td>大文件大并发</td><td>功能丰富的 CoW</td></tr><tr><td>journal</td><td>成熟稳定</td><td>元数据日志,扩展性强</td><td>CoW 天然免 journal</td></tr><tr><td>扩容</td><td>在线扩容可以,缩容支持有限</td><td>在线扩容成熟,<strong>不能缩容</strong></td><td>灵活</td></tr><tr><td>特色</td><td>均衡、省心</td><td>大目录、高并发元数据操作强</td><td>快照、校验和、子卷、压缩</td></tr><tr><td>默认采用</td><td>Debian/Ubuntu 等</td><td>RHEL/CentOS</td><td>openSUSE、Fedora(桌面)</td></tr></tbody></table><p>人话版:</p><ul><li><strong>ext4</strong>:不知道选什么就选它。小文件、普通服务器表现均衡,坑都被踩平了。</li><li><strong>XFS</strong>:日志、对象存储、数据库数据盘、大容量磁盘——元数据并发和大文件是它的主场。记住它不能缩容,分区前想清楚。</li><li><strong>btrfs</strong>:CoW(copy-on-write,改数据不覆盖原地,写新块再切指针)带来快照、校验、子卷这些 ext4 给不了的能力,代价是运维复杂度和写放大。<strong>数据库放 btrfs 要谨慎压测</strong>——CoW 和数据库自己的 WAL 叠起来,写放大可能很难看。</li></ul><hr><h2 id="七、小文件地狱" tabindex="-1">七、小文件地狱 <a class="header-anchor" href="#七、小文件地狱" aria-label="Permalink to &quot;七、小文件地狱&quot;">​</a></h2><p>还有一种事故和&quot;写得快不快&quot;无关,和&quot;文件有多少个&quot;有关。某服务把用户上传按&quot;一个对象一个文件&quot;存,两年攒了八千万个 4KB 文件,然后:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 磁盘容量还剩 40%</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # inode 使用率 100%!</span></span></code></pre></div><p><strong>空间没满,inode 先耗尽了</strong>——新文件一个也建不了,报错还是误导性的 &quot;No space left on device&quot;。这是小文件海量堆积的众多症状之一:</p><ul><li>inode 数量逼近文件系统上限(格式化时就定死了)</li><li>dentry / inode cache 内存压力大(用 <code>slabtop</code> 能看到这两项暴涨)</li><li>元数据 IO 远多于数据 IO,磁盘忙的全是&quot;管理费&quot;</li><li>每次创建文件都要 fsync 目录,成本线性上涨</li><li>备份、遍历、rsync 慢到怀疑人生</li></ul><p>排查三件套:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                          # inode 用量</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> wc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 数文件</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slabtop</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                        # 看 dentry / inode_cache 内存</span></span></code></pre></div><p>工业界的答案高度一致:<strong>别让文件系统替你管海量小对象</strong>。对象存储和日志系统都会把小文件合并进大文件(segment / SSTable),自己在应用层维护索引——LSM 树系的存储引擎本质上就是对&quot;文件系统不擅长小文件&quot;这个事实的绕行。</p><hr><h2 id="八、排查工具箱" tabindex="-1">八、排查工具箱 <a class="header-anchor" href="#八、排查工具箱" aria-label="Permalink to &quot;八、排查工具箱&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 空间 / inode</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> column</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 挂载参数(journal 模式、noatime 等都在这)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">findmnt</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 更清晰的挂载树</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iostat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 设备级:util%、await、吞吐</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pidstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">           # 进程级:谁在读写</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">filefrag</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 文件碎片程度</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">              # inode 号、链接数、时间戳一次看全</span></span></code></pre></div><p>定位思路:<code>iostat</code> 看设备是不是真忙 → <code>pidstat -d</code> 找到是谁 → <code>strace</code> 看它在做什么样的 IO(大量小 write?疯狂 fsync?)→ 回到代码改写法。</p><hr><h2 id="踩坑提醒" tabindex="-1">踩坑提醒 <a class="header-anchor" href="#踩坑提醒" aria-label="Permalink to &quot;踩坑提醒&quot;">​</a></h2><ol><li><strong>&quot;write 成功 = 数据安全&quot;</strong>——进程崩溃数据不丢(已在内核),但机器断电就丢;持久化必须 fsync,没有例外。</li><li><strong>fsync 了文件,没 fsync 目录</strong>——create / rename 产生的目录项更新也是数据;断电后文件内容在、名字没了,等于没在。</li><li><strong>直接覆盖写配置文件</strong>——写一半挂掉就是半截文件;永远走 write temp + fsync + rename + fsync 目录的套路。</li><li><strong>以为 journal 保护你的数据</strong>——默认 <code>data=ordered</code> 只保文件系统结构不坏,你的数据内容仍归 fsync 管,分工别搞混。</li><li><strong>海量小文件不当回事</strong>——inode 耗尽时 <code>df -h</code> 还有空间,报错却说没空间;<code>df -i</code> 要进巡检清单。</li><li><strong>把 tmpfs 当持久化存储</strong>——它是内存,重启即蒸发;只适合缓存和临时文件。</li><li><strong>NFS 当本地盘用</strong>——延迟、缓存一致性、锁语义全都不同,本地盘上正确的代码到 NFS 上未必正确。</li><li><strong>数据库随手放上 CoW 文件系统</strong>——CoW 写放大叠加数据库自己的 WAL,性能可能断崖;上线前必须压测。</li></ol><hr><p>下一篇:<code>20-IO五种模型.md</code>,讲&quot;数据还没准备好时线程怎么办&quot;这个问题的五种答案——阻塞、非阻塞、IO 多路复用、信号驱动、异步 IO,以及被用乱了的&quot;同步/异步&quot;和&quot;阻塞/非阻塞&quot;到底怎么区分。</p>`,74)])])}const g=a(p,[["render",e]]);export{c as __pageData,g as default};
